parameters.functionCode:
// Enhanced scoring with updated patterns
const priorityPatterns = {
  // High priority - AI/Claude focus
  'claude|anthropic|opus': 4.0,
  'claude.?code|mcp|tool.?use': 3.5,
  'gpt.?5|openai|chatgpt': 3.0,

  // Security
  'zero.?day|breach|exploit': 4.0,
  'security|vulnerability|cve': 3.5,

  // AI/ML
  'llm|agent|rag|embedding': 2.5,
  'fine.?tun|train|model': 2.0,
  'breakthrough|paper|research': 2.0,

  // Tools
  'obsidian|notion|pkm': 2.0,
  'python|rust|typescript': 1.5,
  'release|update|new.?feature': 1.5,

  // Prediction markets
  'polymarket|prediction.?market|forecast': 3.0,
  'mispriced|edge|calibrat|superforecast': 3.5,
  'quotient|polyglobe|trenchfu': 2.5
};

const reputableSources = [
  'arxiv.org', 'openai.com', 'anthropic.com',
  'github.com', 'github.blog', 'hackerone.com',
  'lobste.rs', 'substack.com', 'simonwillison.net',
  'gwern.net', 'thehackernews.com'
];

return items.map(item => {
  let score = 0;
  let reasons = [];
  const text = `${item.json.title} ${item.json.content || ''}`.toLowerCase();

  // Apply pattern scoring
  for (const [pattern, weight] of Object.entries(priorityPatterns)) {
    if (new RegExp(pattern, 'i').test(text)) {
      score += weight;
      reasons.push(`Matches: ${pattern}`);
    }
  }

  // Source reputation
  const source = new URL(item.json.link).hostname;
  if (reputableSources.some(s => source.includes(s))) {
    score += 1.5;
    reasons.push(`Trusted: ${source}`);
  }

  // YouTube bonus (your liked channels)
  if (source.includes('youtube.com')) {
    score += 1.0;
    reasons.push('YouTube channel');
  }

  item.json.score = Math.min(score, 10.0);
  item.json.scoreReasons = reasons;
  item.json.needsDeepAnalysis = score >= 5.0;

  // Detect content type
  if (source.includes('youtube.com')) {
    item.json.contentType = 'video';
  } else if (source.includes('arxiv.org')) {
    item.json.contentType = 'paper';
  } else if (source.includes('substack.com')) {
    item.json.contentType = 'article';
  } else {
    item.json.contentType = 'article';
  }

  return item;
});

